from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismSetConfigNode(BaseNode):
    name = "Prism: Set Config"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("category", "string", widget_type="text", default="globals")
        self.add_input("key", "string", widget_type="text", default="")
        self.add_input("value", "any")
        self.add_input("config_scope", "string", widget_type="dropdown", options=["user","project","shared"], default="user")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        cat = inputs.get('category') or ''
        key = inputs.get('key') or ''
        value = inputs.get('value')
        scope = inputs.get('config_scope') or 'user'
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'success': False}
        try:
            ok = False
            if hasattr(core, 'setConfig'):
                try:
                    core.setConfig(cat, key, value, config=scope)
                except TypeError:
                    core.setConfig(cat, key, value)
                ok = True
            elif hasattr(core, 'configs') and hasattr(core.configs, 'setConfig'):
                core.configs.setConfig(cat, key, value, config=scope)
                ok = True
            if ok:
                self.log_success(f"Config[{scope}][{cat}][{key}] <- {value!r}")
                await self.set_output('exec_out', True)
            return {'success': ok}
        except Exception as e:
            self.log_error(f"setConfig failed: {e}")
            return {'success': False}

def register_node():
    return PrismSetConfigNode
